solution: ```class Solution {
public:
    bool backspaceCompare(string s, string t) {
        int i = (int)s.size() - 1, j = (int)t.size() - 1;
        while (i >= 0 || j >= 0) {
            int skip = 0;
            while (i >= 0) {
                if (s[i] == '#') { ++skip; --i; }
                else if (skip) { --skip; --i; }
                else break;
            }
            skip = 0;
            while (j >= 0) {
                if (t[j] == '#') { ++skip; --j; }
                else if (skip) { --skip; --j; }
                else break;
            }
            if (i >= 0 && j >= 0 && s[i] == t[j]) { --i; --j; }
            else return i == -1 && j == -1;
        }
        return true;
    }
};
